 14→// ParseFromBytes parses transcript content from a byte slice.
 15→// Uses bufio.Reader to handle arbitrarily long lines.
 16→func ParseFromBytes(content []byte) ([]Line, error) {
 17→	var lines []Line
 18→	reader := bufio.NewReader(bytes.NewReader(content))
 19→
 20→	for {
 21→		lineBytes, err := reader.ReadBytes('\n')
 22→		if err != nil && err != io.EOF {
 23→			return nil, fmt.Errorf("failed to read transcript: %w", err)
 24→		}
 25→
 26→		// Handle empty line or EOF without content
 27→		if len(lineBytes) == 0 {
 28→			if err == io.EOF {
 29→				break
 30→			}
 31→			continue
 32→		}
 33→
 34→		var line Line
 35→		if err := json.Unmarshal(lineBytes, &line); err == nil {
 36→			lines = append(lines, line)
 37→		}
 38→
 39→		if err == io.EOF {
 40→			break
 41→		}
 42→	}
 43→
 44→	return lines, nil
 45→}
 46→
 47→// SliceFromLine returns the content starting from line number `startLine` (0-indexed).
 48→// This is used to extract only the checkpoint-specific portion of a cumulative transcript.
 49→// For example, if startLine is 2, lines 0 and 1 are skipped and the result starts at line 2.
 50→// Returns empty slice if startLine exceeds the number of lines.
 51→func SliceFromLine(content []byte, startLine int) []byte {
 52→	if len(content) == 0 || startLine <= 0 {
 53→		return content
 54→	}
 55→
 56→	// Find the byte offset where startLine begins
 57→	lineCount := 0
 58→	offset := 0
 59→	for i, b := range content {
 60→		if b == '\n' {
 61→			lineCount++
 62→			if lineCount == startLine {
 63→				offset = i + 1
 64→				break
 65→			}
 66→		}
 67→	}
 68→
 69→	// If we didn't find enough lines, return empty
 70→	if lineCount < startLine {
 71→		return nil
 72→	}
 73→
 74→	// If offset is beyond content, return empty
 75→	if offset >= len(content) {
 76→		return nil
 77→	}
 78→
 79→	return content[offset:]
 80→}
