 82→// ExtractUserContent extracts user content from a raw message.
 83→// Handles both string and array content formats.
 84→// IDE-injected context tags (like <ide_opened_file>) are stripped from the result.
 85→// Returns empty string if the message cannot be parsed or contains no text.
 86→func ExtractUserContent(message json.RawMessage) string {
 87→	var msg UserMessage
 88→	if err := json.Unmarshal(message, &msg); err != nil {
 89→		return ""
 90→	}
 91→
 92→	// Handle string content
 93→	if str, ok := msg.Content.(string); ok {
 94→		return textutil.StripIDEContextTags(str)
 95→	}
 96→
 97→	// Handle array content (only if it contains text blocks)
 98→	if arr, ok := msg.Content.([]interface{}); ok {
 99→		var texts []string
100→		for _, item := range arr {
101→			if m, ok := item.(map[string]interface{}); ok {
102→				if m["type"] == ContentTypeText {
103→					if text, ok := m["text"].(string); ok {
104→						texts = append(texts, text)
105→					}
106→				}
107→			}
108→		}
109→		if len(texts) > 0 {
110→			return textutil.StripIDEContextTags(strings.Join(texts, "\n\n"))
111→		}
112→	}
113→
114→	return ""
115→}
