224→// extractUserPrompts extracts all user messages from the transcript in order.
225→// Only considers messages with string content (not tool results).
226→// IDE-injected context tags (like <ide_opened_file>) are stripped from the results.
227→func extractUserPrompts(transcript []transcriptLine) []string {
228→	var prompts []string
229→	for i := range transcript {
230→		if transcript[i].Type != transcriptTypeUser {
231→			continue
232→		}
233→		var msg userMessage
234→		if err := json.Unmarshal(transcript[i].Message, &msg); err != nil {
235→			continue
236→		}
237→
238→		// Handle string content
239→		if str, ok := msg.Content.(string); ok {
240→			prompts = append(prompts, textutil.StripIDEContextTags(str))
241→			continue
242→		}
243→
244→		// Handle array content (only if it contains text blocks)
245→		if arr, ok := msg.Content.([]interface{}); ok {
246→			var texts []string
247→			for _, item := range arr {
248→				if m, ok := item.(map[string]interface{}); ok {
249→					if m["type"] == contentTypeText {
250→						if text, ok := m["text"].(string); ok {
251→							texts = append(texts, text)
252→						}
253→					}
254→				}
255→			}
256→			if len(texts) > 0 {
257→				prompts = append(prompts, textutil.StripIDEContextTags(strings.Join(texts, "\n\n")))
258→			}
259→		}
260→	}
261→	return prompts
262→}
263→
264→// extractLastUserPrompt extracts the last user message from the transcript.
265→// Only considers messages with string content (not tool results).
266→// IDE-injected context tags (like <ide_opened_file>) are stripped from the result.
267→func extractLastUserPrompt(transcript []transcriptLine) string {
268→	prompts := extractUserPrompts(transcript)
269→	if len(prompts) == 0 {
270→		return ""
271→	}
272→	return prompts[len(prompts)-1]
273→}
274→
275→// extractLastAssistantMessage extracts the last text message from the assistant
276→func extractLastAssistantMessage(transcript []transcriptLine) string {
277→	for i := len(transcript) - 1; i >= 0; i-- {
278→		if transcript[i].Type == transcriptTypeAssistant {
279→			var msg assistantMessage
280→			if err := json.Unmarshal(transcript[i].Message, &msg); err != nil {
281→				continue
282→			}
283→
284→			for _, block := range msg.Content {
285→				if block.Type == contentTypeText && block.Text != "" {
286→					return block.Text
287→				}
288→			}
289→		}
290→	}
291→	return ""
292→}
293→
294→// findLastUserUUID finds the UUID of the last user message (that has string content)
295→func findLastUserUUID(transcript []transcriptLine) string {
296→	for i := len(transcript) - 1; i >= 0; i-- {
297→		if transcript[i].Type == transcriptTypeUser {
298→			var msg userMessage
299→			if err := json.Unmarshal(transcript[i].Message, &msg); err != nil {
300→				continue
301→			}
302→			// Only count messages with string content (not tool results)
303→			if _, ok := msg.Content.(string); ok {
304→				return transcript[i].UUID
305→			}
306→		}
307→	}
308→	return ""
309→}
310→
311→// filterTranscriptAfterUUID returns transcript lines after the given UUID
312→func filterTranscriptAfterUUID(transcript []transcriptLine, uuid string) []transcriptLine {
313→	if uuid == "" {
314→		return transcript
315→	}
316→
317→	foundIndex := -1
318→	for i, line := range transcript {
319→		if line.UUID == uuid {
320→			foundIndex = i
321→			break
322→		}
323→	}
324→
325→	if foundIndex == -1 || foundIndex == len(transcript)-1 {
326→		return transcript
327→	}
328→
329→	return transcript[foundIndex+1:]
330→}
