378→// extractKeyActions extracts key actions from the transcript for context file
379→func extractKeyActions(transcript []transcriptLine, maxActions int) []string {
380→	var keyActions []string
381→
382→	for _, line := range transcript {
383→		if line.Type == transcriptTypeAssistant {
384→			var msg assistantMessage
385→			if err := json.Unmarshal(line.Message, &msg); err != nil {
386→				continue
387→			}
388→
389→			for _, block := range msg.Content {
390→				if block.Type == contentTypeToolUse {
391→					var input toolInput
392→					_ = json.Unmarshal(block.Input, &input) //nolint:errcheck // Best-effort parsing for display purposes
393→
394→					detail := input.Description
395→					if detail == "" {
396→						detail = input.Command
397→					}
398→					if detail == "" {
399→						detail = input.FilePath
400→					}
401→					if detail == "" {
402→						detail = input.Pattern
403→					}
404→
405→					action := "- **" + block.Name + "**: " + detail
406→					keyActions = append(keyActions, action)
407→					if len(keyActions) >= maxActions {
408→						return keyActions
409→					}
410→				}
411→			}
412→		}
413→	}
414→
415→	return keyActions
416→}
