480→// writeTranscript writes transcript lines to a file in JSONL format.
481→func writeTranscript(path string, transcript []transcriptLine) error {
482→	file, err := os.Create(path) //nolint:gosec // Writing to controlled git metadata path
483→	if err != nil {
484→		return fmt.Errorf("failed to create file: %w", err)
485→	}
486→	defer func() { _ = file.Close() }()
487→
488→	for _, line := range transcript {
489→		data, err := json.Marshal(line)
490→		if err != nil {
491→			return fmt.Errorf("failed to marshal line: %w", err)
492→		}
493→		if _, err := file.Write(data); err != nil {
494→			return fmt.Errorf("failed to write line: %w", err)
495→		}
496→		if _, err := file.WriteString("\n"); err != nil {
497→			return fmt.Errorf("failed to write newline: %w", err)
498→		}
499→	}
500→
501→	return nil
502→}
