504→// TranscriptPosition contains the position information for a transcript file.
505→type TranscriptPosition struct {
506→	LastUUID  string // Last non-empty UUID (from user/assistant messages)
507→	LineCount int    // Total number of lines
508→}
509→
510→// GetTranscriptPosition reads a transcript file and returns the last UUID and line count.
511→// Returns empty position if file doesn't exist or is empty.
512→// Only considers UUIDs from actual messages (user/assistant), not summary rows which use leafUuid.
513→func GetTranscriptPosition(path string) (TranscriptPosition, error) {
514→	if path == "" {
515→		return TranscriptPosition{}, nil
516→	}
517→
518→	file, err := os.Open(path) //nolint:gosec // Reading from controlled transcript path
519→	if err != nil {
520→		if os.IsNotExist(err) {
521→			return TranscriptPosition{}, nil
522→		}
523→		return TranscriptPosition{}, fmt.Errorf("failed to open transcript: %w", err)
524→	}
525→	defer func() { _ = file.Close() }()
526→
527→	var pos TranscriptPosition
528→	reader := bufio.NewReader(file)
529→
530→	for {
531→		lineBytes, err := reader.ReadBytes('\n')
532→		if err != nil && err != io.EOF {
533→			return TranscriptPosition{}, fmt.Errorf("failed to read transcript: %w", err)
534→		}
535→
536→		if len(lineBytes) == 0 {
537→			if err == io.EOF {
538→				break
539→			}
540→			continue
541→		}
542→
543→		pos.LineCount++
544→
545→		// Parse line to extract UUID (only from user/assistant messages, not summaries)
546→		var line transcriptLine
547→		if err := json.Unmarshal(lineBytes, &line); err == nil {
548→			if line.UUID != "" {
549→				pos.LastUUID = line.UUID
550→			}
551→		}
552→
553→		if err == io.EOF {
554→			break
555→		}
556→	}
557→
558→	return pos, nil
559→}
