  1→package claudecode
  2→
  3→import (
  4→	"bufio"
  5→	"bytes"
  6→	"encoding/json"
  7→	"fmt"
  8→	"os"
  9→	"path/filepath"
 10→	"strings"
 11→
 12→	"github.com/entireio/cli/cmd/entire/cli/agent"
 13→	"github.com/entireio/cli/cmd/entire/cli/transcript"
 14→)
 15→
 16→// TranscriptLine is an alias to the shared transcript.Line type.
 17→type TranscriptLine = transcript.Line
 18→
 19→// Type aliases for internal use.
 20→type (
 21→	userMessage      = transcript.UserMessage
 22→	assistantMessage = transcript.AssistantMessage
 23→	toolInput        = transcript.ToolInput
 24→)
 25→
 26→// Scanner buffer size for large transcript files (10MB)
 27→const scannerBufferSize = 10 * 1024 * 1024
 28→
 29→// ParseTranscript parses raw JSONL content into transcript lines
 30→func ParseTranscript(data []byte) ([]TranscriptLine, error) {
 31→	var lines []TranscriptLine
 32→	scanner := bufio.NewScanner(bytes.NewReader(data))
 33→	scanner.Buffer(make([]byte, 0, scannerBufferSize), scannerBufferSize)
 34→
 35→	for scanner.Scan() {
 36→		var line TranscriptLine
 37→		if err := json.Unmarshal(scanner.Bytes(), &line); err != nil {
 38→			continue // Skip malformed lines
 39→		}
 40→		lines = append(lines, line)
 41→	}
 42→
 43→	if err := scanner.Err(); err != nil {
 44→		return nil, fmt.Errorf("failed to scan transcript: %w", err)
 45→	}
 46→	return lines, nil
 47→}
 48→
 49→// SerializeTranscript converts transcript lines back to JSONL bytes
 50→func SerializeTranscript(lines []TranscriptLine) ([]byte, error) {
 51→	var buf bytes.Buffer
 52→	for _, line := range lines {
 53→		data, err := json.Marshal(line)
 54→		if err != nil {
 55→			return nil, fmt.Errorf("failed to marshal line: %w", err)
 56→		}
 57→		buf.Write(data)
 58→		buf.WriteByte('\n')
 59→	}
 60→	return buf.Bytes(), nil
 61→}
 62→
 63→// ExtractModifiedFiles extracts files modified by tool calls from transcript
 64→func ExtractModifiedFiles(lines []TranscriptLine) []string {
 65→	fileSet := make(map[string]bool)
 66→	var files []string
 67→
 68→	for _, line := range lines {
 69→		if line.Type != "assistant" {
 70→			continue
 71→		}
 72→
 73→		var msg assistantMessage
 74→		if err := json.Unmarshal(line.Message, &msg); err != nil {
 75→			continue
 76→		}
 77→
 78→		for _, block := range msg.Content {
 79→			if block.Type != "tool_use" {
 80→				continue
 81→			}
 82→
 83→			// Check if it's a file modification tool
 84→			isModifyTool := false
 85→			for _, name := range FileModificationTools {
 86→				if block.Name == name {
 87→					isModifyTool = true
 88→					break
 89→				}
 90→			}
 91→
 92→			if !isModifyTool {
 93→				continue
 94→			}
 95→
 96→			var input toolInput
 97→			if err := json.Unmarshal(block.Input, &input); err != nil {
 98→				continue
 99→			}
100→
101→			file := input.FilePath
102→			if file == "" {
103→				file = input.NotebookPath
104→			}
105→
106→			if file != "" && !fileSet[file] {
107→				fileSet[file] = true
108→				files = append(files, file)
109→			}
110→		}
111→	}
112→
113→	return files
114→}
