116→// ExtractLastUserPrompt extracts the last user message from transcript
117→func ExtractLastUserPrompt(lines []TranscriptLine) string {
118→	for i := len(lines) - 1; i >= 0; i-- {
119→		if lines[i].Type != "user" { //nolint:goconst // already present in codebase
120→			continue
121→		}
122→
123→		var msg userMessage
124→		if err := json.Unmarshal(lines[i].Message, &msg); err != nil {
125→			continue
126→		}
127→
128→		// Handle string content
129→		if str, ok := msg.Content.(string); ok {
130→			return str
131→		}
132→
133→		// Handle array content (text blocks)
134→		if arr, ok := msg.Content.([]interface{}); ok {
135→			var texts []string
136→			for _, item := range arr {
137→				if m, ok := item.(map[string]interface{}); ok {
138→					if m["type"] == "text" {
139→						if text, ok := m["text"].(string); ok {
140→							texts = append(texts, text)
141→						}
142→					}
143→				}
144→			}
145→			if len(texts) > 0 {
146→				return strings.Join(texts, "\n\n")
147→			}
148→		}
149→	}
150→	return ""
151→}
