202→// CalculateTokenUsage calculates token usage from a Claude Code transcript.
203→// This is specific to Claude/Anthropic's API format where each assistant message
204→// contains a usage object with input_tokens, output_tokens, and cache tokens.
205→//
206→// Due to streaming, multiple transcript rows may share the same message.id.
207→// We deduplicate by taking the row with the highest output_tokens for each message.id.
208→func CalculateTokenUsage(transcript []TranscriptLine) *agent.TokenUsage {
209→	// Map from message.id to the usage with highest output_tokens
210→	usageByMessageID := make(map[string]messageUsage)
211→
212→	for _, line := range transcript {
213→		if line.Type != "assistant" {
214→			continue
215→		}
216→
217→		var msg messageWithUsage
218→		if err := json.Unmarshal(line.Message, &msg); err != nil {
219→			continue
220→		}
221→
222→		if msg.ID == "" {
223→			continue
224→		}
225→
226→		// Keep the entry with highest output_tokens (final streaming state)
227→		existing, exists := usageByMessageID[msg.ID]
228→		if !exists || msg.Usage.OutputTokens > existing.OutputTokens {
229→			usageByMessageID[msg.ID] = msg.Usage
230→		}
231→	}
232→
233→	// Sum up all unique messages
234→	usage := &agent.TokenUsage{
235→		APICallCount: len(usageByMessageID),
236→	}
237→	for _, u := range usageByMessageID {
238→		usage.InputTokens += u.InputTokens
239→		usage.CacheCreationTokens += u.CacheCreationInputTokens
240→		usage.CacheReadTokens += u.CacheReadInputTokens
241→		usage.OutputTokens += u.OutputTokens
242→	}
243→
244→	return usage
245→}
