247→// CalculateTokenUsageFromFile calculates token usage from a Claude Code transcript file.
248→// If startLine > 0, only considers lines from startLine onwards.
249→func CalculateTokenUsageFromFile(path string, startLine int) (*agent.TokenUsage, error) {
250→	if path == "" {
251→		return &agent.TokenUsage{}, nil
252→	}
253→
254→	transcript, err := parseTranscriptFromLine(path, startLine)
255→	if err != nil {
256→		return nil, err
257→	}
258→
259→	return CalculateTokenUsage(transcript), nil
260→}
261→
262→// parseTranscriptFromLine parses a transcript file starting from a specific line.
263→func parseTranscriptFromLine(path string, startLine int) ([]TranscriptLine, error) {
264→	file, err := os.Open(path) //nolint:gosec // Path comes from Claude Code transcript location
265→	if err != nil {
266→		return nil, fmt.Errorf("failed to open transcript file: %w", err)
267→	}
268→	defer file.Close()
269→
270→	var lines []TranscriptLine
271→	scanner := bufio.NewScanner(file)
272→	scanner.Buffer(make([]byte, 0, scannerBufferSize), scannerBufferSize)
273→
274→	lineNum := 0
275→	for scanner.Scan() {
276→		if lineNum < startLine {
277→			lineNum++
278→			continue
279→		}
280→		lineNum++
281→
282→		var line TranscriptLine
283→		if err := json.Unmarshal(scanner.Bytes(), &line); err != nil {
284→			continue // Skip malformed lines
285→		}
286→		lines = append(lines, line)
287→	}
288→
289→	if err := scanner.Err(); err != nil {
290→		return nil, fmt.Errorf("failed to scan transcript: %w", err)
291→	}
292→
293→	return lines, nil
294→}
