431→// ExtractAllModifiedFiles extracts files modified by both the main agent and
432→// any subagents spawned via the Task tool. It parses the main transcript from
433→// startLine, collects modified files from the main agent, then reads each
434→// subagent's transcript from subagentsDir to collect their modified files too.
435→// The result is a deduplicated list of all modified file paths.
436→func ExtractAllModifiedFiles(transcriptPath string, startLine int, subagentsDir string) ([]string, error) {
437→	if transcriptPath == "" {
438→		return nil, nil
439→	}
440→
441→	// Parse main transcript once
442→	transcript, err := parseTranscriptFromLine(transcriptPath, startLine)
443→	if err != nil {
444→		return nil, fmt.Errorf("failed to parse transcript: %w", err)
445→	}
446→
447→	// Collect modified files from main agent
448→	fileSet := make(map[string]bool)
449→	var files []string
450→	for _, f := range ExtractModifiedFiles(transcript) {
451→		if !fileSet[f] {
452→			fileSet[f] = true
453→			files = append(files, f)
454→		}
455→	}
456→
457→	// Find spawned subagents and collect their modified files
458→	agentIDs := ExtractSpawnedAgentIDs(transcript)
459→	for agentID := range agentIDs {
460→		agentPath := filepath.Join(subagentsDir, fmt.Sprintf("agent-%s.jsonl", agentID))
461→		agentTranscript, err := parseTranscriptFromLine(agentPath, 0)
462→		if err != nil {
463→			// Subagent transcript may not exist yet or may have been cleaned up
464→			continue
465→		}
466→		for _, f := range ExtractModifiedFiles(agentTranscript) {
467→			if !fileSet[f] {
468→				fileSet[f] = true
469→				files = append(files, f)
470→			}
471→		}
472→	}
473→
474→	return files, nil
475→}
