 58→func runDebugAutoCommit(w io.Writer, transcriptPath string) error {
 59→	// Check if we're in a git repository
 60→	repoRoot, err := paths.RepoRoot()
 61→	if err != nil {
 62→		fmt.Fprintln(w, "Not in a git repository")
 63→		return nil //nolint:nilerr // not being in a git repo is expected, not an error for status check
 64→	}
 65→	fmt.Fprintf(w, "Repository: %s\n\n", repoRoot)
 66→
 67→	// Print strategy info
 68→	strat := GetStrategy()
 69→	isAutoCommit := strat.Name() == strategy.StrategyNameAutoCommit
 70→	printStrategyInfo(w, strat, isAutoCommit)
 71→
 72→	// Print session state
 73→	currentSession := printSessionState(w)
 74→
 75→	// Auto-detect transcript if not provided
 76→	if transcriptPath == "" && currentSession != "" {
 77→		detected, detectErr := findTranscriptForSession(currentSession)
 78→		if detectErr != nil {
 79→			fmt.Fprintf(w, "\nCould not auto-detect transcript: %v\n", detectErr)
 80→		} else if detected != "" {
 81→			transcriptPath = detected
 82→			fmt.Fprintf(w, "\nAuto-detected transcript: %s\n", transcriptPath)
 83→		}
 84→	}
 85→
 86→	// Print file changes and get total
 87→	fmt.Fprintln(w, "\n=== File Changes ===")
 88→	var totalChanges int
 89→	if transcriptPath != "" {
 90→		totalChanges = printTranscriptChanges(w, transcriptPath, currentSession, repoRoot)
 91→	} else {
 92→		var err error
 93→		totalChanges, err = printGitStatusChanges(w)
 94→		if err != nil {
 95→			return err
 96→		}
 97→	}
 98→
 99→	// Print decision
100→	printDecision(w, isAutoCommit, strat.Name(), totalChanges)
101→
102→	// Print transcript location help if we couldn't find one
103→	if transcriptPath == "" {
104→		printTranscriptHelp(w)
105→	}
106→
107→	return nil
108→}
