166→func printTranscriptChanges(w io.Writer, transcriptPath, currentSession, repoRoot string) int {
167→	fmt.Fprintf(w, "\nParsing transcript: %s\n", transcriptPath)
168→
169→	var modifiedFromTranscript, newFiles, deletedFiles []string
170→
171→	// Parse transcript
172→	transcript, err := parseTranscript(transcriptPath)
173→	if err != nil {
174→		fmt.Fprintf(w, "  Error parsing transcript: %v\n", err)
175→	} else {
176→		modifiedFromTranscript = extractModifiedFiles(transcript)
177→		fmt.Fprintf(w, "  Found %d modified files in transcript\n", len(modifiedFromTranscript))
178→	}
179→	// Compute new and deleted files (single git status call)
180→	// Load preState only if we have an active session (needed for new file detection)
181→	var preState *PrePromptState
182→	if currentSession != "" {
183→		var loadErr error
184→		preState, loadErr = LoadPrePromptState(currentSession)
185→		if loadErr != nil {
186→			fmt.Fprintf(w, "  Error loading pre-prompt state: %v\n", loadErr)
187→		}
188→	}
189→	// Always call DetectFileChanges - deleted files don't depend on preState
190→	fileChanges, err := DetectFileChanges(preState.PreUntrackedFiles())
191→	if err != nil {
192→		fmt.Fprintf(w, "  Error computing file changes: %v\n", err)
193→	}
194→	if fileChanges != nil {
195→		newFiles = fileChanges.New
196→		deletedFiles = fileChanges.Deleted
197→	}
198→
199→	// Filter and normalize paths
200→	modifiedFromTranscript = FilterAndNormalizePaths(modifiedFromTranscript, repoRoot)
201→	newFiles = FilterAndNormalizePaths(newFiles, repoRoot)
202→	deletedFiles = FilterAndNormalizePaths(deletedFiles, repoRoot)
203→
204→	// Print files
205→	printFileList(w, "Modified (from transcript)", "M", modifiedFromTranscript)
206→	printFileList(w, "New files (created during session)", "+", newFiles)
207→	printFileList(w, "Deleted files", "D", deletedFiles)
208→
