 82→// ParseHookInput parses Claude Code hook input from stdin.
 83→func (c *ClaudeCodeAgent) ParseHookInput(hookType agent.HookType, reader io.Reader) (*agent.HookInput, error) {
 84→	data, err := io.ReadAll(reader)
 85→	if err != nil {
 86→		return nil, fmt.Errorf("failed to read input: %w", err)
 87→	}
 88→
 89→	if len(data) == 0 {
 90→		return nil, errors.New("empty input")
 91→	}
 92→
 93→	input := &agent.HookInput{
 94→		HookType:  hookType,
 95→		Timestamp: time.Now(),
 96→		RawData:   make(map[string]interface{}),
 97→	}
 98→
 99→	// Parse based on hook type
100→	switch hookType {
101→	case agent.HookUserPromptSubmit:
102→		var raw userPromptSubmitRaw
103→		if err := json.Unmarshal(data, &raw); err != nil {
104→			return nil, fmt.Errorf("failed to parse user prompt submit: %w", err)
105→		}
106→		input.SessionID = raw.SessionID
107→		input.SessionRef = raw.TranscriptPath
108→		input.UserPrompt = raw.Prompt
109→
110→	case agent.HookSessionStart, agent.HookSessionEnd, agent.HookStop:
111→		var raw sessionInfoRaw
112→		if err := json.Unmarshal(data, &raw); err != nil {
113→			return nil, fmt.Errorf("failed to parse session info: %w", err)
114→		}
115→		input.SessionID = raw.SessionID
116→		input.SessionRef = raw.TranscriptPath
117→
118→	case agent.HookPreToolUse:
119→		var raw taskHookInputRaw
120→		if err := json.Unmarshal(data, &raw); err != nil {
121→			return nil, fmt.Errorf("failed to parse pre-tool input: %w", err)
122→		}
123→		input.SessionID = raw.SessionID
124→		input.SessionRef = raw.TranscriptPath
125→		input.ToolUseID = raw.ToolUseID
126→		input.ToolInput = raw.ToolInput
127→
128→	case agent.HookPostToolUse:
129→		var raw postToolHookInputRaw
130→		if err := json.Unmarshal(data, &raw); err != nil {
131→			return nil, fmt.Errorf("failed to parse post-tool input: %w", err)
132→		}
133→		input.SessionID = raw.SessionID
134→		input.SessionRef = raw.TranscriptPath
135→		input.ToolUseID = raw.ToolUseID
136→		input.ToolInput = raw.ToolInput
137→		// Store agent ID in raw data for Task tool results
138→		if raw.ToolResponse.AgentID != "" {
139→			input.RawData["agent_id"] = raw.ToolResponse.AgentID
140→		}
141→	}
142→
143→	return input, nil
144→}
