176→// ReadSession reads a session from Claude's storage (JSONL transcript file).
177→// The session data is stored in NativeData as raw JSONL bytes.
178→// ModifiedFiles is computed by parsing the transcript.
179→func (c *ClaudeCodeAgent) ReadSession(input *agent.HookInput) (*agent.AgentSession, error) {
180→	if input.SessionRef == "" {
181→		return nil, errors.New("session reference (transcript path) is required")
182→	}
183→
184→	// Read the raw JSONL file
185→	data, err := os.ReadFile(input.SessionRef)
186→	if err != nil {
187→		return nil, fmt.Errorf("failed to read transcript: %w", err)
188→	}
189→
190→	// Parse to extract computed fields
191→	lines, err := ParseTranscript(data)
192→	if err != nil {
193→		return nil, fmt.Errorf("failed to parse transcript: %w", err)
194→	}
195→
196→	return &agent.AgentSession{
197→		SessionID:     input.SessionID,
198→		AgentName:     c.Name(),
199→		SessionRef:    input.SessionRef,
200→		StartTime:     time.Now(),
201→		NativeData:    data,
202→		ModifiedFiles: ExtractModifiedFiles(lines),
203→	}, nil
204→}
