206→// WriteSession writes a session to Claude's storage (JSONL transcript file).
207→// Uses the NativeData field which contains raw JSONL bytes.
208→// The session must have been created by Claude Code (AgentName check).
209→func (c *ClaudeCodeAgent) WriteSession(session *agent.AgentSession) error {
210→	if session == nil {
211→		return errors.New("session is nil")
212→	}
213→
214→	// Verify this session belongs to Claude Code
215→	if session.AgentName != "" && session.AgentName != c.Name() {
216→		return fmt.Errorf("session belongs to agent %q, not %q", session.AgentName, c.Name())
217→	}
218→
219→	if session.SessionRef == "" {
220→		return errors.New("session reference (transcript path) is required")
221→	}
222→
223→	if len(session.NativeData) == 0 {
224→		return errors.New("session has no native data to write")
225→	}
226→
227→	// Write the raw JSONL data
228→	if err := os.WriteFile(session.SessionRef, session.NativeData, 0o600); err != nil {
229→		return fmt.Errorf("failed to write transcript: %w", err)
230→	}
231→
232→	return nil
233→}
