257→// TruncateAtUUID returns a new session truncated at the given UUID (inclusive).
258→// This is used for rewind operations to restore transcript state.
259→// Requires NativeData to be populated.
260→func (c *ClaudeCodeAgent) TruncateAtUUID(session *agent.AgentSession, uuid string) (*agent.AgentSession, error) {
261→	if session == nil {
262→		return nil, errors.New("session is nil")
263→	}
264→
265→	if len(session.NativeData) == 0 {
266→		return nil, errors.New("session has no native data")
267→	}
268→
269→	if uuid == "" {
270→		// No truncation needed, return copy
271→		return &agent.AgentSession{
272→			SessionID:     session.SessionID,
273→			AgentName:     session.AgentName,
274→			RepoPath:      session.RepoPath,
275→			SessionRef:    session.SessionRef,
276→			StartTime:     session.StartTime,
277→			NativeData:    session.NativeData,
278→			ModifiedFiles: session.ModifiedFiles,
279→		}, nil
280→	}
281→
282→	// Parse, truncate, re-serialize
283→	lines, err := ParseTranscript(session.NativeData)
284→	if err != nil {
285→		return nil, fmt.Errorf("failed to parse transcript: %w", err)
286→	}
287→
288→	truncated := TruncateAtUUID(lines, uuid)
289→
290→	newData, err := SerializeTranscript(truncated)
291→	if err != nil {
292→		return nil, fmt.Errorf("failed to serialize truncated transcript: %w", err)
293→	}
294→
295→	return &agent.AgentSession{
296→		SessionID:     session.SessionID,
297→		AgentName:     session.AgentName,
298→		RepoPath:      session.RepoPath,
299→		SessionRef:    session.SessionRef,
300→		StartTime:     session.StartTime,
301→		NativeData:    newData,
302→		ModifiedFiles: ExtractModifiedFiles(truncated),
303→	}, nil
304→}
