424→// TranscriptChunker interface implementation
425→
426→// ChunkTranscript splits a JSONL transcript at line boundaries.
427→// Claude Code uses JSONL format (one JSON object per line), so chunking
428→// is done at newline boundaries to preserve message integrity.
429→func (c *ClaudeCodeAgent) ChunkTranscript(content []byte, maxSize int) ([][]byte, error) {
430→	chunks, err := agent.ChunkJSONL(content, maxSize)
431→	if err != nil {
432→		return nil, fmt.Errorf("failed to chunk JSONL transcript: %w", err)
433→	}
434→	return chunks, nil
435→}
436→
437→// ReassembleTranscript concatenates JSONL chunks with newlines.
438→//
439→//nolint:unparam // error return is required by interface, kept for consistency
440→func (c *ClaudeCodeAgent) ReassembleTranscript(chunks [][]byte) ([]byte, error) {
441→	return agent.ReassembleJSONL(chunks), nil
442→}
