133→// ExtractAllPromptResponses extracts all user prompt and assistant response pairs from a transcript.
134→// Returns pairs in chronological order (oldest first).
135→// Each pair contains the user's prompt, assistant's text response, and files modified.
136→func ExtractAllPromptResponses(transcript []transcriptLine) []PromptResponsePair {
137→	var pairs []PromptResponsePair
138→
139→	// Find all user prompts (messages with string content, not tool results)
140→	var userIndices []int
141→	for i, line := range transcript {
142→		if line.Type == transcriptTypeUser {
143→			var msg userMessage
144→			if err := json.Unmarshal(line.Message, &msg); err != nil {
145→				continue
146→			}
147→			// Only count messages with string content (real user prompts)
148→			if _, ok := msg.Content.(string); ok {
149→				userIndices = append(userIndices, i)
150→			} else if arr, ok := msg.Content.([]interface{}); ok {
151→				// Check if array has text blocks (also a real user prompt)
152→				for _, item := range arr {
153→					if m, ok := item.(map[string]interface{}); ok {
154→						if m["type"] == contentTypeText {
155→							userIndices = append(userIndices, i)
156→							break
157→						}
158→					}
159→				}
160→			}
161→		}
162→	}
163→
164→	// For each user prompt, extract the prompt text, following assistant response, and files
165→	for idx, userIdx := range userIndices {
166→		// Determine the range for this prompt's conversation
167→		endIdx := len(transcript)
168→		if idx < len(userIndices)-1 {
169→			endIdx = userIndices[idx+1]
170→		}
171→
172→		// Extract prompt text
173→		prompt := extractUserPromptAt(transcript, userIdx)
174→		if prompt == "" {
175→			continue
176→		}
177→
178→		// Extract assistant responses and files from this range
179→		slice := transcript[userIdx:endIdx]
180→		responses := extractAssistantResponses(slice)
181→		files := extractModifiedFiles(slice)
182→
183→		pairs = append(pairs, PromptResponsePair{
184→			Prompt:    prompt,
185→			Responses: responses,
186→			Files:     files,
187→		})
188→	}
189→
190→	return pairs
191→}
