169→// toolResultBlock represents a tool_result in a user message
170→type toolResultBlock struct {
171→	Type      string `json:"type"`
172→	ToolUseID string `json:"tool_use_id"`
173→}
174→
175→// userMessageWithToolResults represents a user message that may contain tool results
176→type userMessageWithToolResults struct {
177→	Content []toolResultBlock `json:"content"`
178→}
179→
180→// FindCheckpointUUID finds the UUID of the message containing the tool_result
181→// for the given tool_use_id
182→func FindCheckpointUUID(lines []TranscriptLine, toolUseID string) (string, bool) {
183→	for _, line := range lines {
184→		if line.Type != "user" {
185→			continue
186→		}
187→
188→		var msg userMessageWithToolResults
189→		if err := json.Unmarshal(line.Message, &msg); err != nil {
190→			continue
191→		}
192→
193→		for _, block := range msg.Content {
194→			if block.Type == "tool_result" && block.ToolUseID == toolUseID {
195→				return line.UUID, true
196→			}
197→		}
198→	}
199→	return "", false
200→}
