296→// ExtractSpawnedAgentIDs extracts agent IDs from Task tool results in a transcript.
297→// When a Task tool completes, the tool_result contains "agentId: <id>" in its content.
298→// Returns a map of agentID -> toolUseID for all spawned agents.
299→func ExtractSpawnedAgentIDs(transcript []TranscriptLine) map[string]string {
300→	agentIDs := make(map[string]string)
301→
302→	for _, line := range transcript {
303→		if line.Type != "user" {
304→			continue
305→		}
306→
307→		// Parse as array of content blocks (tool results)
308→		var contentBlocks []struct {
309→			Type      string          `json:"type"`
310→			ToolUseID string          `json:"tool_use_id"`
311→			Content   json.RawMessage `json:"content"`
312→		}
313→
314→		var msg struct {
315→			Content json.RawMessage `json:"content"`
316→		}
317→		if err := json.Unmarshal(line.Message, &msg); err != nil {
318→			continue
319→		}
320→
321→		if err := json.Unmarshal(msg.Content, &contentBlocks); err != nil {
322→			continue
323→		}
324→
325→		for _, block := range contentBlocks {
326→			if block.Type != "tool_result" {
327→				continue
328→			}
329→
330→			// Content can be a string or array of text blocks
331→			var textContent string
332→
333→			// Try as array of text blocks first
334→			var textBlocks []struct {
335→				Type string `json:"type"`
336→				Text string `json:"text"`
337→			}
338→			if err := json.Unmarshal(block.Content, &textBlocks); err == nil {
339→				var textContentSb361 strings.Builder
340→				for _, tb := range textBlocks {
341→					if tb.Type == "text" {
342→						textContentSb361.WriteString(tb.Text + "\n")
343→					}
344→				}
345→				textContent += textContentSb361.String()
346→			} else {
347→				// Try as plain string
348→				var str string
349→				if err := json.Unmarshal(block.Content, &str); err == nil {
350→					textContent = str
351→				}
352→			}
353→
354→			// Look for agentId in the text
355→			if agentID := extractAgentIDFromText(textContent); agentID != "" {
356→				agentIDs[agentID] = block.ToolUseID
357→			}
358→		}
359→	}
360→
361→	return agentIDs
362→}
363→
364→// extractAgentIDFromText extracts an agent ID from text containing "agentId: <id>".
365→func extractAgentIDFromText(text string) string {
366→	const prefix = "agentId: "
367→	idx := strings.Index(text, prefix)
368→	if idx == -1 {
369→		return ""
370→	}
371→
372→	// Extract the ID (alphanumeric characters after the prefix)
373→	start := idx + len(prefix)
374→	end := start
375→	for end < len(text) && (text[end] >= 'a' && text[end] <= 'z' ||
376→		text[end] >= 'A' && text[end] <= 'Z' ||
377→		text[end] >= '0' && text[end] <= '9') {
378→		end++
379→	}
380→
381→	if end > start {
382→		return text[start:end]
383→	}
384→	return ""
385→}
386→
387→// CalculateTotalTokenUsage calculates token usage for a turn, including subagents.
388→// It parses the main transcript from startLine, extracts spawned agent IDs,
389→// and calculates their token usage from transcripts in subagentsDir.
390→func CalculateTotalTokenUsage(transcriptPath string, startLine int, subagentsDir string) (*agent.TokenUsage, error) {
391→	if transcriptPath == "" {
392→		return &agent.TokenUsage{}, nil
393→	}
394→
395→	// Parse transcript ONCE
396→	transcript, err := parseTranscriptFromLine(transcriptPath, startLine)
397→	if err != nil {
398→		return nil, fmt.Errorf("failed to parse transcript: %w", err)
399→	}
400→
401→	// Calculate token usage from parsed transcript
402→	mainUsage := CalculateTokenUsage(transcript)
403→
404→	// Extract spawned agent IDs from the same parsed transcript
405→	agentIDs := ExtractSpawnedAgentIDs(transcript)
406→
407→	// Calculate subagent token usage
408→	if len(agentIDs) > 0 {
409→		subagentUsage := &agent.TokenUsage{}
410→		for agentID := range agentIDs {
411→			agentPath := filepath.Join(subagentsDir, fmt.Sprintf("agent-%s.jsonl", agentID))
412→			agentUsage, err := CalculateTokenUsageFromFile(agentPath, 0)
413→			if err != nil {
414→				// Agent transcript may not exist yet or may have been cleaned up
415→				continue
416→			}
417→			subagentUsage.InputTokens += agentUsage.InputTokens
418→			subagentUsage.CacheCreationTokens += agentUsage.CacheCreationTokens
419→			subagentUsage.CacheReadTokens += agentUsage.CacheReadTokens
420→			subagentUsage.OutputTokens += agentUsage.OutputTokens
421→			subagentUsage.APICallCount += agentUsage.APICallCount
422→		}
423→		if subagentUsage.APICallCount > 0 {
424→			mainUsage.SubagentTokens = subagentUsage
425→		}
426→	}
427→
428→	return mainUsage, nil
429→}
430→
431→// ExtractAllModifiedFiles extracts files modified by both the main agent and
432→// any subagents spawned via the Task tool. It parses the main transcript from
433→// startLine, collects modified files from the main agent, then reads each
434→// subagent's transcript from subagentsDir to collect their modified files too.
435→// The result is a deduplicated list of all modified file paths.
436→func ExtractAllModifiedFiles(transcriptPath string, startLine int, subagentsDir string) ([]string, error) {
437→	if transcriptPath == "" {
438→		return nil, nil
439→	}
440→
441→	// Parse main transcript once
442→	transcript, err := parseTranscriptFromLine(transcriptPath, startLine)
443→	if err != nil {
444→		return nil, fmt.Errorf("failed to parse transcript: %w", err)
445→	}
446→
447→	// Collect modified files from main agent
448→	fileSet := make(map[string]bool)
449→	var files []string
450→	for _, f := range ExtractModifiedFiles(transcript) {
451→		if !fileSet[f] {
452→			fileSet[f] = true
453→			files = append(files, f)
454→		}
455→	}
456→
457→	// Find spawned subagents and collect their modified files
458→	agentIDs := ExtractSpawnedAgentIDs(transcript)
459→	for agentID := range agentIDs {
460→		agentPath := filepath.Join(subagentsDir, fmt.Sprintf("agent-%s.jsonl", agentID))
461→		agentTranscript, err := parseTranscriptFromLine(agentPath, 0)
462→		if err != nil {
463→			// Subagent transcript may not exist yet or may have been cleaned up
464→			continue
465→		}
466→		for _, f := range ExtractModifiedFiles(agentTranscript) {
467→			if !fileSet[f] {
468→				fileSet[f] = true
469→				files = append(files, f)
470→			}
471→		}
472→	}
473→
474→	return files, nil
475→}
